import{_ as e,o as r,c as d,a2 as a}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"Providers","description":"Managing AI API providers in WebRouter","frontmatter":{"title":"Providers","description":"Managing AI API providers in WebRouter"},"headers":[],"relativePath":"guide/providers.md","filePath":"guide/providers.md"}'),i={name:"guide/providers.md"};function o(n,t,l,s,c,h){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="providers" tabindex="-1">Providers <a class="header-anchor" href="#providers" aria-label="Permalink to &quot;Providers&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Providers represent your AI API sources. WebRouter supports multiple provider types, each with different capabilities.</p><h2 id="provider-types" tabindex="-1">Provider Types <a class="header-anchor" href="#provider-types" aria-label="Permalink to &quot;Provider Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th style="text-align:center;">Health</th><th style="text-align:center;">Latency</th><th style="text-align:center;">Cost Data</th><th style="text-align:center;">Channel Mgmt</th></tr></thead><tbody><tr><td><code>direct</code></td><td>Official APIs (OpenAI, Anthropic, Google, DeepSeek, etc.)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><code>aggregate</code></td><td>Aggregator platforms (OpenRouter, API2D, OhMyGPT, etc.)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">Manual</td><td style="text-align:center;">—</td></tr><tr><td><code>newapi</code></td><td>Self-hosted New-API / One-API</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>litellm</code></td><td>LiteLLM proxy</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><code>custom</code></td><td>Any OpenAI-compatible gateway</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr></tbody></table><h2 id="adding-a-provider" tabindex="-1">Adding a Provider <a class="header-anchor" href="#adding-a-provider" aria-label="Permalink to &quot;Adding a Provider&quot;">​</a></h2><ol><li>Navigate to <strong>Providers</strong> → <strong>+ Add</strong></li><li>Select the provider type</li><li>Enter the Base URL and API Key</li><li>Specify available models (comma-separated)</li><li>Configure weight and priority for routing</li><li>Click <strong>Save</strong></li></ol><h2 id="health-checks" tabindex="-1">Health Checks <a class="header-anchor" href="#health-checks" aria-label="Permalink to &quot;Health Checks&quot;">​</a></h2><p>WebRouter automatically checks provider health every 5 minutes:</p><ul><li><strong>Healthy:</strong> Provider responds within normal latency</li><li><strong>Warning:</strong> High latency or intermittent failures</li><li><strong>Dead:</strong> Provider unresponsive, enters cooldown</li></ul><p>Dead providers are automatically excluded from routing until they recover.</p><h2 id="provider-status" tabindex="-1">Provider Status <a class="header-anchor" href="#provider-status" aria-label="Permalink to &quot;Provider Status&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>healthy</code></td><td>Responding normally</td></tr><tr><td><code>warning</code></td><td>High latency or degraded</td></tr><tr><td><code>dead</code></td><td>Unreachable (in cooldown)</td></tr><tr><td><code>unknown</code></td><td>Not yet checked</td></tr><tr><td><code>auth_failed</code></td><td>Authentication error</td></tr></tbody></table>',13)])])}const y=e(i,[["render",o]]);export{p as __pageData,y as default};
